# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import boto3

sns = boto3.client('sns')

def lambda_handler(event, context):
    sns_topic_arn = event['topicArn']
    message_content = event['messageContent']
    message_type = event['notificationType']

    if message_type == 'critical':
        subject = f"[CRITICAL] {event['eventName']} - {event['entityName']}"
        message = json.dumps(event)
    elif message_type == 'info':
        subject = f"Informational notification for {event['eventName']} - {event['entityName']}"
        message = json.dumps(event)
    else:
        subject = "Unknown Notification"
        message = json.dumps({
            'NotificationType': event['notificationType'],
            'Error': 'Invalid notification type'
        })

    try:
        response = sns.publish(
            TopicArn=sns_topic_arn,
            Subject=subject,
            Message=message
        )
        return {
            'statusCode': 200,
            'statusMessage': 'SNS message published successfully',
            'response': response
        }
    except Exception as e:
        print(f'Error publishing SNS message: {str(e)}')
        return {
            'statusCode': 500,
            'statusMessage': 'Error publishing SNS message'
        }